// ─── Datos de regiones y sedes de INSECAP ────────────────────────────────────

export interface Sede {
  nombre: string;
  direccion: string;
  ciudad: string;
  tipo: 'fisica' | 'virtual';
}

export interface Region {
  id: string;
  nombre: string;
  ciudad: string;
  color: string;
  colorHover: string;
  colorActive: string;
  tipo: 'virtual' | 'fisica' | 'ambas';
  sedes: Sede[];
  /** Coordenadas del pin en el SVG (solo sedes fisicas) */
  pinX?: number;
  pinY?: number;
}

